mapper.insert:
/** UsptEtcCareerDao.insert */
insert into uspt_etc_career
	(
		etc_career_id
		, member_id
		, career_nm
		, career_type_cd
		, bgnde
		, endde
		, cn
		, instt
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{etcCareerId}
		, #{memberId}
		, #{careerNm}
		, #{careerTypeCd}
		, #{bgnde}
		, #{endde}
		, #{cn}
		, #{instt}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	)

mapper.update:
/** UsptEtcCareerDao.update */
update uspt_etc_career
set
	career_nm		 = #{careerNm}
	, career_type_cd = #{careerTypeCd}
	, bgnde			 = #{bgnde}
	, endde			 = #{endde}
	, cn			 = #{cn}
	, instt			 = #{instt}
	, updater_id	 = #{updaterId}
	, updated_dt	 = #{updatedDt}
where
	member_id = #{memberId}
	and etc_career_id = #{etcCareerId}

